import React, { useState, useEffect } from "react";
import { Box, Drawer, Typography, TextField, Button } from "@mui/material";
import StarIcon from '@mui/icons-material/Star';

const FeedbackDrawer = ({
    open,
    onClose,
    onSubmit,
    onAddDakshina,
    onNewJourney
}) => {
    const [rating, setRating] = useState(0);
    const [feedback, setFeedback] = useState("");
    const [submitted, setSubmitted] = useState(false);

    // Reset state when drawer becomes closed to avoid flashing old data on next open
    // or use a separate effect for individual resets if needed.
    useEffect(() => {
        if (!open) {
            setRating(0);
            setFeedback("");
            setSubmitted(false);
        }
    }, [open]);

    const handleSubmit = () => {
        setSubmitted(true);
        if (onSubmit) {
            onSubmit(rating, feedback);
        }
    };

    return (
        <Drawer
            anchor="bottom"
            open={open}
            onClose={onClose}
            ModalProps={{ keepMounted: true }}
            PaperProps={{
                sx: {
                    bgcolor: "#5AA270",
                    borderTopLeftRadius: 20,
                    borderTopRightRadius: 20,
                    px: 3.5,
                    pt: 5,
                    pb: 1.5,
                    maxWidth: 450,
                    mx: "auto",
                    minHeight: submitted ? 250 : 'auto', // Ensure height for success message
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: submitted ? 'center' : 'flex-start'
                },
            }}
        >
            {!submitted ? (
                <>
                    <Typography
                        sx={{
                            textAlign: "center",
                            color: "#fff",
                            fontSize: 16,
                            mb: 1,
                            // fontWeight: 400,
                        }}
                    >
