                    </Typography>

                    {/* Stars */}
                    <Box display="flex" justifyContent="center" mb={0}>
                        {[1, 2, 3, 4, 5].map((star) => (
                            <Box
                                key={star}
                                onClick={() => setRating(star)}
                                sx={{
                                    mx: .3,
                                    mb: 1,
                                    cursor: "pointer",
                                    color: star <= rating ? "#fff" : "rgba(255,255,255,0.4)",
                                    transition: "0.2s",
