                    setSendingWaitMessage("");
                    setLoading(false);
                    return;
                }
            }

            const errMsg = err.response?.data?.detail || err.message || 'Guruji is not available right now. Please try again after some time.';
            setMessages(prev => [...prev, {
                role: 'assistant',
                assistant: 'maya',
                content: errMsg,
                time: getCurrentTime()
            }]);
            setIsSendingToBackend(false);
            setSendingWaitMessage("");
        } finally {
