                                            </Typography>

                                            <Box sx={{
                                                display: 'flex',
                                                alignItems: 'flex-start',
                                                gap: 1.5,
                                                flexDirection: msg.role === 'user' ? 'row-reverse' : 'row',
                                                maxWidth: '100%',

                                            }}>
                                                {msg.content && msg.content.trim() !== '' && (
                                                    <Box sx={{
                                                        p: '12px 16px 18px 12px',
                                                        borderRadius: '10px 2px 10px 10px',
                                                        borderRight: (msg.role === 'user' && (msg.requires_chat_payment || isSubscribed)) || (msg.role === 'assistant' && (isPaidUserMsg || isSubscribed))
                                                            ? '2.5px solid #54A170'
                                                            : 'none',
                                                        bgcolor: msg.role === 'user'
                                                            ? (msg.requires_chat_payment || isSubscribed ? '#2f3148' : '#e2e2e2')
                                                            : (isPaidUserMsg || isSubscribed ? '#fef6eb' : '#f1f1f1'),
                                                        cursor: (msg.isQueued && isLastQueuedMsg && !isUserTyping && msg.role === 'user') ? 'pointer' : 'default',
                                                        pointerEvents: (msg.isQueued && isLastQueuedMsg && !isUserTyping && msg.role === 'user') ? 'auto' : 'inherit',
                                                        color: msg.role === 'user'
                                                            ? (msg.requires_chat_payment || isSubscribed ? '#ffffff' : '#000000')
                                                            : (isPaidUserMsg || isSubscribed ? '#3e2723' : '#000000'),
                                                        position: 'relative',
                                                        maxWidth: '325px',
                                                        minWidth: '100px',
                                                        width: 'fit-content',
                                                        overflowWrap: "break-word",
                                                        wordBreak: "break-word",
                                                        whiteSpace: "pre-line",
                                                        fontSize: "0.9rem",
                                                    }}
                                                        onClick={(msg.isQueued && isLastQueuedMsg && !isUserTyping && msg.role === 'user') ? handleEditQueuedMessage : undefined}
                                                    >
                                                        <SafeHTML
                                                            html={msg.content}
                                                        />

                                                        {/* JSON Output View (for regular messages) */}
                                                        {((msg.mayaJson && !msg.gurujiJson && jsonVisibility.maya) || (msg.psycologyJson && jsonVisibility.psycology) || (msg.gurujiInput && jsonVisibility.guruji)) && (
                                                            <Box sx={{ mt: 1, pt: 1, borderTop: '1px dashed rgba(0,0,0,0.1)', textAlign: 'right', display: 'flex', gap: 2, justifyContent: 'flex-end' }}>
                                                                {(msg.mayaJson && !msg.gurujiJson && jsonVisibility.maya) && (
                                                                    <Typography
                                                                        onClick={() => handleLabelClick(msg.mayaJson, 'RECEPTIONIST CLASSIFICATION')}
                                                                        sx={{
                                                                            fontSize: '0.65rem',
                                                                            color: '#F36A2F',
                                                                            fontWeight: 800,
                                                                            cursor: 'pointer',
                                                                            textTransform: 'uppercase',
                                                                            textDecoration: 'underline',
                                                                            '&:hover': { opacity: 0.8 }
                                                                        }}
                                                                    >
                                                                        Maya JSON
                                                                    </Typography>
                                                                )}
                                                                {(msg.psycologyJson && jsonVisibility.psycology) && (
                                                                    <Typography
                                                                        onClick={() => handleLabelClick(msg.psycologyJson, 'USER PSYCHOLOGY')}
                                                                        sx={{
                                                                            fontSize: '0.65rem',
                                                                            color: '#F36A2F',
                                                                            fontWeight: 800,
                                                                            cursor: 'pointer',
                                                                            textTransform: 'uppercase',
                                                                            textDecoration: 'underline',
                                                                            '&:hover': { opacity: 0.8 }
                                                                        }}
                                                                    >
                                                                        Psychology
                                                                    </Typography>
                                                                )}
                                                                {(msg.gurujiInput && jsonVisibility.guruji) && (
                                                                    <Typography
                                                                        onClick={() => handleLabelClick(msg.gurujiInput, 'ASTROLOGER INPUT JSON')}
                                                                        sx={{
                                                                            fontSize: '0.65rem',
                                                                            color: '#F36A2F',
                                                                            fontWeight: 800,
                                                                            cursor: 'pointer',
                                                                            textTransform: 'uppercase',
                                                                            textDecoration: 'underline',
                                                                            '&:hover': { opacity: 0.8 }
                                                                        }}
                                                                    >
                                                                        Guruji Input
                                                                    </Typography>
                                                                )}
                                                            </Box>
                                                        )}

                                                        {/* Additional Debug Labels for Regular Guruji Bubble */}
                                                        {(msg.assistant === 'guruji' && jsonVisibility.guruji) && (
                                                            <Box sx={{ mt: 1, pt: 1, borderTop: '1px dashed rgba(255,255,255,0.2)', display: 'flex', gap: 1.5, justifyContent: 'flex-end' }}>
                                                                {msg.context && (
                                                                    <Typography
                                                                        onClick={() => handleLabelClick(msg.context, 'RAG CHUNKS')}
                                                                        sx={{
                                                                            fontSize: '0.65rem',
                                                                            color: 'rgba(255,255,255,0.7)',
                                                                            fontWeight: 800,
                                                                            cursor: 'pointer',
                                                                            textTransform: 'uppercase',
                                                                            textDecoration: 'underline',
                                                                            '&:hover': { color: 'white' }
                                                                        }}
                                                                    >
                                                                        RAG
                                                                    </Typography>
                                                                )}
                                                                {msg.metrics && (
                                                                    <Typography
                                                                        onClick={() => handleLabelClick(msg.metrics, 'MODELLING METRICS')}
                                                                        sx={{
                                                                            fontSize: '0.65rem',
                                                                            color: 'rgba(255,255,255,0.8)',
                                                                            fontWeight: 800,
                                                                            cursor: 'pointer',
                                                                            textTransform: 'uppercase',
                                                                            textDecoration: 'underline',
                                                                            '&:hover': { color: 'white' }
                                                                        }}
                                                                    >
                                                                        Modelling %
                                                                    </Typography>
                                                                )}
                                                                {(jsonVisibility.guruji || jsonVisibility.maya) && (
                                                                    <Typography
                                                                        onClick={() => setLogsOpen(true)}
                                                                        sx={{
                                                                            fontSize: '0.65rem',
                                                                            color: 'rgba(255,255,255,0.8)',
                                                                            fontWeight: 800,
                                                                            cursor: 'pointer',
                                                                            textTransform: 'uppercase',
                                                                            textDecoration: 'underline',
                                                                            '&:hover': { color: 'white' }
                                                                        }}
                                                                    >
                                                                        Logs
                                                                    </Typography>
                                                                )}
                                                            </Box>
                                                        )}


                                                        {/* Timestamp moved inside the bubble */}
                                                        <Box
                                                            sx={{
                                                                fontSize: '10px',
                                                                opacity: 0.8,
                                                                position: 'absolute',
                                                                bottom: 2,
                                                                right: 8,
                                                                color: msg.role === 'user' ? (msg.requires_chat_payment ? 'rgba(255,255,255,0.7)' : '#494848') : '#494848',
                                                                fontWeight: 500,
                                                                pt: 1,
                                                                display: 'flex',
                                                                alignItems: 'center'
                                                            }}
                                                        >
                                                            {msg.time}
                                                            {(!isAnimating || msg.role !== 'user') && renderStatusTicks(i)}
                                                        </Box>

                                                    </Box>

                                                )}

                                            </Box>
                                        </Box>
                                        {/* timer animation for user msg */}
                                        <Box
                                            sx={{
                                                width: (msg.isQueued && isLastQueuedMsg && !isUserTyping && msg.role === 'user') ? 45 : 0,
                                                opacity: (msg.isQueued && isLastQueuedMsg && !isUserTyping && msg.role === 'user') ? 1 : 0,
                                                overflow: 'hidden',
                                                transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
                                                display: 'flex',
                                                justifyContent: 'center',
                                                alignItems: 'center',
                                                position: 'relative',
                                                top: '15px',
                                                pointerEvents: (msg.isQueued && isLastQueuedMsg && !isUserTyping && msg.role === 'user') ? 'auto' : 'none',
                                                zIndex: 10,
                                            }}
                                        >
                                            <Box
                                                key={msg.arrivalTime}
                                                onClick={handleEditQueuedMessage}
                                                sx={{
                                                    m: 0,
                                                    display: "flex",
                                                    justifyContent: "flex-end",
                                                    alignItems: "center",
                                                    backgroundColor: "transparent",
                                                    cursor: "pointer",
                                                    p: .5,
                                                    minWidth: 40,
                                                }}
                                            >
                                                <Box
                                                    sx={{
                                                        position: "relative",
                                                        width: 40,
                                                        height: 40,
                                                        overflow: "hidden",
                                                    }}
                                                >
                                                    <Box
                                                        component="svg"
                                                        viewBox="0 0 36 36"
                                                        sx={{
                                                            transform: "rotate(-90deg)",
                                                            width: 30,
                                                            height: 30,
                                                            display: "block",
                                                        }}
                                                    >
                                                        {/* Background circle */}
                                                        <Box
                                                            component="circle"
                                                            cx="18"
                                                            cy="18"
                                                            r="15"
                                                            sx={{
                                                                fill: "none",
                                                                strokeWidth: 3,
                                                                stroke: "#eeeeee",
                                                            }}
                                                        />

                                                        {/* Animated border circle */}
                                                        <Box
                                                            component="circle"
                                                            cx="18"
                                                            cy="18"
                                                            r="15"
                                                            sx={{
                                                                fill: "none",
                                                                strokeWidth: 3,
                                                                stroke: "#1C1F46",
                                                                strokeLinecap: "round",
                                                                strokeDasharray: 95,
                                                                strokeDashoffset: 95,
                                                                animation: "fillBorder 3s linear forwards",
                                                            }}
                                                        />
                                                    </Box>

                                                    {/* Close icon */}
                                                    <Box
                                                        sx={{
                                                            position: "absolute",
                                                            top: "35%",
                                                            left: "42%",
                                                            width: 13,
                                                            height: 13,
                                                            transform: "translate(-50%, -50%)",

                                                            "&::before, &::after": {
                                                                content: '""',
                                                                position: "absolute",
                                                                top: "50%",
                                                                left: 0,
                                                                width: "100%",
                                                                height: "2px",
                                                                backgroundColor: "#1C1F46",
                                                                borderRadius: "1px",
                                                            },

                                                            "&::before": {
                                                                transform: "rotate(45deg)",
                                                            },

                                                            "&::after": {
                                                                transform: "rotate(-45deg)",
                                                            },
                                                        }}
                                                    />

                                                    {/* keyframes */}
                                                    <Box
                                                        sx={{
                                                            "@keyframes fillBorder": {
                                                                from: { strokeDashoffset: 95 },
                                                                to: { strokeDashoffset: 0 },
                                                            },
                                                        }}
                                                    />
                                                </Box>
                                            </Box>
                                        </Box>
                                    </Box>
                                    {/* Translation Indicator */}
                                    {showTranslationIndicator && (
                                        <TranslationIndicator
                                            text={msg.role === 'user'
                                                ? `Translated to astrologer's language by MAYA AI`
                                                : `Translated to your language / language style by MAYA AI`
                                            }
                                        />
                                    )}
                                </Box>
                            )}
                        </UserMessageTimer>
                    );
                })}

                {/* Dot Loader + Astrologer status overlay - 3 distinct phases */}
                {(isSendingToBackend || forceShowTyping) && userMsgPhase === 2 && (() => {
                    const isMayaPhase = !sendingWaitMessage || sendingWaitMessage === "Sending to Maya";
                    const isReadingPhase = sendingWaitMessage === "Sending to Astrologer" || sendingWaitMessage === "Sending to astrologer" || sendingWaitMessage === "Astrologer is reading your message";
                    const isTypingPhase = sendingWaitMessage === "Astrologer is typing";

                    // Pre-typing: 2s into reading phase, start showing 'Astrologer is typing' early
                    const timeInReading = readingPhaseStartTime ? (currentTime - readingPhaseStartTime) : 0;
                    const showPreTyping = isReadingPhase && timeInReading >= 2000;

                    if (!isMayaPhase && !isReadingPhase && !isTypingPhase) return null;

                    // Effective phases for rendering
                    const showDots = isMayaPhase;
                    const showReading = isReadingPhase && !showPreTyping;
                    const showTyping = isTypingPhase || showPreTyping;

                    return (
                        <Box sx={{
                            position: 'fixed',
                            bottom: showDots ? 30 : 18,
                            left: 0,
                            right: 0,
                            mx: 'auto',
                            width: 'max-content',
                            display: 'flex',
                            justifyContent: 'center',
                            alignItems: 'center',
                            zIndex: 10000,
                            pointerEvents: 'none',
                            minWidth: '180px',
                            ...(showDots || showReading ? {
                                bgcolor: 'transparent',
                            } : {
                                // bgcolor: '#67687a',
                                bgcolor: '#f1f1f1',
                                borderRadius: '2px 10px 10px 10px',
                                color: '#000',
                                px: 3,
                                py: 0.8,
                                minHeight: 20,
                            })
                        }}>
                            {showDots ? (
                                /* Phase 1: 3-dot loader while Maya processes */
                                <Box sx={{ display: 'flex', gap: '5px', alignItems: 'center' }}>
                                    {[0, 1, 2].map((i) => (
                                        <Box
                                            key={i}
                                            component="span"
                                            sx={{
                                                width: 5,
                                                height: 5,
                                                backgroundColor: '#646577',
                                                borderRadius: '50%',
                                                display: 'inline-block',
                                                "@keyframes micro-pulse": {
                                                    "0%, 80%, 100%": { transform: 'scale(0.8)', opacity: 0.35 },
                                                    "40%": { transform: 'scale(1.2)', backgroundColor: '#a0a3ab', opacity: 1 }
                                                },
                                                animation: 'micro-pulse 1s ease-in-out infinite both',
                                                animationDelay: i === 0 ? '-0.32s' : i === 1 ? '-0.16s' : '0s',
                                            }}
                                        />
                                    ))}
                                </Box>
                            ) : showReading ? (
                                /* Phase 2: "Astrologer is reading your message" (first 2s of reading phase) */
                                <Box
                                    component="span"
                                    sx={{
                                        fontFamily: "'Roboto', sans-serif",
                                        fontSize: "12px",
                                        fontWeight: 500,
                                        color: "#fff",
                                        display: "block",
                                        whiteSpace: "nowrap",
                                        overflow: "hidden",
                                        borderRight: "2px solid transparent",
                                        width: 0,
                                        mb: 1,
                                        maxWidth: "fit-content",
                                        "@keyframes reading": {
                                            "0%": { width: 0, opacity: 1 },
                                            "70%": { width: "100%" },
                                            "95%": { width: "100%", opacity: 1 },
                                            "99%": { width: 0, opacity: 0 },
                                            "100%": { width: 0, opacity: 0 },
                                        },
                                        // "@keyframes cursor-blink": {
                                        //     "0%, 100%": { borderColor: "transparent" },
                                        //     "50%": { borderColor: "#fff" },
                                        // },
                                        animation: "reading 4s linear infinite",
                                    }}
                                >
                                    Astrologer is reading your message
                                </Box>
                            ) : (
                                /* Phase 3: "Astrologer is typing" typewriter animation */
                                <Box
                                    component="span"
                                    sx={{
                                        fontFamily: "'Roboto', sans-serif",
                                        fontSize: "12px",
                                        fontWeight: 500,
                                        color: "#2F3148",
                                        display: "block",
                                        whiteSpace: "nowrap",
                                        overflow: "hidden",
                                        borderRight: "2px solid #2F3148",
                                        width: 0,
                                        maxWidth: "fit-content",
                                        "@keyframes human-typing": {
                                            "0%": { width: 0, opacity: 1 },
                                            "12%": { width: "5em" },
                                            "20%": { width: "5em" },
                                            "45%": { width: "9.5em" },
                                            "55%": { width: "9.5em" },
                                            "75%": { width: "100%" },
                                            "98%": { width: "100%", opacity: 1 },
                                            "99%": { width: 0, opacity: 0 },
                                            "100%": { width: 0, opacity: 0 },
                                        },
                                        "@keyframes cursor-blink": {
                                            "0%, 100%": { borderColor: "transparent" },
                                            "50%": { borderColor: "#2F3148" },
                                        },
                                        animation: "human-typing 7s linear infinite, cursor-blink 0.8s step-end infinite",
                                    }}
                                >
                                    Astrologer is typing
                                </Box>
                            )}
                        </Box>
                    );
                })()}



                {!chatStarted && messages.length === 0 && (
                    <>
                        <Box sx={{
                            flex: isMovingToTop ? 0 : 1,
                            maxHeight: isMovingToTop ? 0 : '100%',
                            transition: 'all 0.8s cubic-bezier(0.4, 0, 0.2, 1)',
                            overflow: 'hidden'
                        }} />
                        <Box sx={{
                            mb: 2,
                            transform: isMovingToTop ? 'translateY(0)' : 'translateY(0)',
                            transition: 'transform 0.8s cubic-bezier(0.4, 0, 0.2, 1)'
                        }}>
                            <MayaIntro
                                // title="Welcome"
                                content={`<b>${userName ? userName.split(' ').map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()).join(' ') : ' '}, welcome.</b>\n\nI'm <b>MAYA</b>, and I'll assist you during your consultation.\n\nWhenever you're ready, you may begin your conversation with <b>Guruji</b> by pressing the button below.\n\nYou may ask about your life, your future, or anything that has been on your mind.`}
                                jsonVisibility={jsonVisibility}
                                onLabelClick={handleLabelClick}
                                sx={{ fontSize: '.9rem', fontWeight: 400 }}
                            />
                        </Box>
                    </>
                )}

                {/* {isConnecting && (
                    <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', py: 4, gap: 2 }}>
                        <CircularProgress size={30} sx={{ color: '#F36A2F' }} />
                        <Typography sx={{ color: '#666', fontSize: '0.9rem', fontWeight: 500 }}>Connecting to Guruji...</Typography>
                    </Box>
                )} */}

                < div ref={messagesEndRef} />
            </Box>

            {!chatStarted && !isConnecting ? (
                <ConsultFooter
                    label="Talk to Guruji"
                    onConsult={handleStartConsultation}
                />
            ) : (chatStarted || isConnecting) ? (
                <ChatInputFooter
                    onSend={handleSend}
                    onTyping={setIsUserTyping}
                    userStatus={userStatus}
                    loading={loading}
                    summary={summary}
                    isAnimating={isAnimating}
                    userMsgPhase={userMsgPhase}
                    inputValue={input}
                    setInputValue={setInput}
                    isBuffering={isSendingToBackend}
                    isConnecting={isConnecting}
                    connectionText={connectionText}
                />
            ) : null}
            {/* Same overlays as before (Inactivity, Summary, Drawer) */}
            {/* ... preserved ... */}

            {/* Inactivity Prompt Overlay */}
            {/* {showInactivityPrompt && !summary && (
                <Box sx={{ position: 'fixed', inset: 0, bgcolor: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(5px)', zIndex: 11000, display: 'flex', alignItems: 'center', justifyContent: 'center', p: 3 }}>
                    <Box sx={{ bgcolor: 'white', p: 4, borderRadius: 4, textAlign: 'center', maxWidth: 400, boxShadow: '0 20px 50px rgba(0,0,0,0.2)', border: '1px solid #F36A2F' }}>
                        <Box sx={{ width: 80, height: 80, bgcolor: '#FFF6EB', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', mx: 'auto', mb: 3 }}>
                            <CancelIcon sx={{ fontSize: 50, color: '#F36A2F' }} />
                        </Box>
                        <Typography variant="h5" sx={{ fontWeight: 800, mb: 1, color: '#333' }}>Still here?</Typography>
                        <Typography variant="body2" sx={{ color: '#666', mb: 4 }}>
                            Guruji is ready when you are. Would you like to wrap up this session and receive your summary?
                        </Typography>
                        <Box sx={{ display: 'flex', gap: 2 }}>
                            <ListItemButton onClick={() => setShowInactivityPrompt(false)} sx={{ borderRadius: 2, textAlign: 'center', justifyContent: 'center', border: '1px solid #ccc' }}>
                                Continue
                            </ListItemButton>
                            <ListItemButton onClick={() => { setShowInactivityPrompt(false); setFeedbackDrawerOpen(true); }} sx={{ borderRadius: 2, textAlign: 'center', justifyContent: 'center', bgcolor: '#F36A2F', color: 'white', '&:hover': { bgcolor: '#FF7A28' } }}>
                                End & Review
                            </ListItemButton>
                        </Box>
                    </Box>
                </Box>
            )} */}

            {/* Summary & Feedback Modal */}
            {
                summary && (
                    <Box sx={{ position: 'fixed', inset: 0, bgcolor: 'rgba(0,0,0,0.7)', backdropFilter: 'blur(8px)', zIndex: 110, display: 'flex', alignItems: 'center', justifyContent: 'center', p: 2 }}>
                        <Box sx={{
                            bgcolor: 'white',
                            p: 4,
                            borderRadius: 5,
                            maxWidth: 500,
                            width: '100%',
                            boxShadow: '0 25px 60px rgba(0,0,0,0.3)',
                            position: 'relative',
                            maxHeight: '90vh',
                            overflowY: 'auto',
                            '&::-webkit-scrollbar': { display: 'none' },
                            msOverflowStyle: 'none',
                            scrollbarWidth: 'none'
                        }}>
                            <Box sx={{ position: 'absolute', top: 0, right: 0, p: 2, zIndex: 2 }}>
                                <img src="/svg/header_stars.svg" style={{ width: 100, opacity: 0.1 }} alt="Stars" />
                            </Box>

                            {!feedbackSubmitted ? (
                                <Box sx={{ position: 'relative', zIndex: 1 }}>
                                    <Typography variant="h5" sx={{ fontWeight: 900, mb: 1, color: '#F36A2F' }}>Session Insights</Typography>
                                    <Typography variant="caption" sx={{ fontWeight: 800, color: '#999', display: 'block', mb: 3 }}>COMPLETED CONSULTATION</Typography>

                                    <Box sx={{ bgcolor: '#FFF6EB', p: 3, borderRadius: 3, borderLeft: '6px solid #F36A2F', mb: 4 }}>
                                        <Typography sx={{ fontStyle: 'italic', fontSize: '0.95rem', color: '#555', lineHeight: 1.7 }}>
                                            "{summary}"
                                        </Typography>
                                    </Box>

                                    <Box sx={{ mb: 4 }}>
                                        <Typography sx={{ fontWeight: 800, color: '#333', mb: 1 }}>Rate Guruji's Wisdom</Typography>
                                        <Rating
                                            value={feedback.rating}
                                            onChange={(_, v) => setFeedback(prev => ({ ...prev, rating: v }))}
                                            size="large"
                                            sx={{ color: '#F36A2F' }}
                                        />
                                        <TextField
                                            fullWidth
                                            multiline
                                            rows={2}
                                            placeholder="Add a thought..."
                                            value={feedback.comment}
                                            onChange={(e) => setFeedback(prev => ({ ...prev, comment: e.target.value }))}
                                            sx={{ mt: 2, '& .MuiOutlinedInput-root': { borderRadius: 2, bgcolor: '#fbfbfb' } }}
                                        />
                                    </Box>

                                    <Box sx={{ display: 'flex', gap: 2 }}>
                                        <ListItemButton onClick={() => setSummary(null)} sx={{ borderRadius: 2, justifyContent: 'center', bgcolor: '#F3F4F6' }}>
                                            Review Chat
                                        </ListItemButton>
                                        <ListItemButton
                                            onClick={handleFeedbackSubmit}
                                            disabled={submittingFeedback || feedback.rating === 0}
                                            sx={{ borderRadius: 2, justifyContent: 'center', bgcolor: '#F36A2F', color: 'white', '&:hover': { bgcolor: '#FF7A28' } }}
                                        >
                                            {submittingFeedback ? <CircularProgress size={20} color="inherit" /> : 'Submit & Close'}
                                        </ListItemButton>
                                    </Box>
                                </Box>
                            ) : (
                                <Box sx={{ textAlign: 'center', py: 4 }}>
                                    <Typography variant="h5" sx={{ fontWeight: 900, mb: 1, color: '#F36A2F' }}>Session Insights</Typography>
                                    <Box sx={{ bgcolor: '#FFF6EB', p: 3, borderRadius: 3, borderLeft: '6px solid #F36A2F', mb: 4, textAlign: 'left' }}>
                                        <Typography sx={{ fontStyle: 'italic', fontSize: '0.95rem', color: '#555', lineHeight: 1.7 }}>
                                            "{summary}"
                                        </Typography>
                                    </Box>

                                    <Box sx={{ width: 80, height: 80, bgcolor: '#E8F5E9', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', mx: 'auto', mb: 3 }}>
                                        <Box sx={{ color: '#4CAF50', fontSize: 40 }}>✓</Box>
                                    </Box>
                                    <Typography variant="h5" sx={{ fontWeight: 900, mb: 1 }}>Gratitude!</Typography>
                                    <Typography variant="body2" sx={{ color: '#666', mb: 4 }}>
                                        Your feedback has been cast into the heavens.
                                    </Typography>
                                    <Box sx={{ display: 'flex', gap: 2, justifyContent: 'center' }}>
                                        <ListItemButton onClick={handleNewChat} sx={{ borderRadius: 2, justifyContent: 'center', bgcolor: '#F36A2F', color: 'white' }}>
                                            New Journey
                                        </ListItemButton>
                                        <ListItemButton onClick={handleLogout} sx={{ borderRadius: 2, justifyContent: 'center', bgcolor: '#f0f0f0' }}>
                                            Logout
                                        </ListItemButton>
                                    </Box>
                                </Box>
                            )}
                        </Box>
                    </Box>
                )
            }


            <style>{`
@keyframes bounce {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-5px); }
}
`}</style>
            <ThankYou
                open={thankYouOpen}
                onClose={() => {
                    setThankYouOpen(false);
                    if (thankYouAction === 'NEW_CHAT') {
                        handleNewChat();
                    }
                    setThankYouAction(null);
                }}
                amount={thankYouData.amount}
                points={thankYouData.points}
                title={thankYouData.title}
                trustMsg={thankYouData.trustMsg}
                gratitudeMsg={thankYouData.gratitudeMsg}
                addedLabel={thankYouData.addedLabel}
                showWave={thankYouData.showWave}
                referenceId={thankYouData.referenceId}
            />

            {/* Initial Loading / Processing Overlay */}
            {/* {userStatus === 'processing' && (
                <Box sx={{
                    position: 'fixed',
                    inset: 0,
                    bgcolor: 'rgba(255,255,255,0.9)',
                    backdropFilter: 'blur(10px)',
                    zIndex: 20000,
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    p: 4,
                    textAlign: 'center'
                }}>
                    <CircularProgress sx={{ color: '#F36A2F', mb: 4, size: 60 }} />
                    <Typography variant="h5" sx={{ fontWeight: 800, color: '#333', mb: 2 }}>
                        Connecting with the Cosmos
                    </Typography>
                    <Typography variant="body1" sx={{ color: '#666', maxWidth: 400 }}>
                        Guruji is currently preparing your personalized astrological charts.
                        Please wait a moment as we align your stars...
                    </Typography>
                </Box>
            )} */}
            {/* Modal for Logs */}
            <Dialog
                open={logsOpen}
                onClose={() => setLogsOpen(false)}
                fullWidth
                maxWidth="sm"
                PaperProps={{
                    sx: {
                        borderRadius: 2,
                        bgcolor: '#1a1a1a',
                        color: '#eee',
                        height: '70vh'
                    }
                }}
            >
                <DialogTitle sx={{ borderBottom: '1px solid #333', py: 1.5, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <Typography variant="h6" sx={{ fontSize: '1rem', fontWeight: 700 }}>SESSION LOGS</Typography>
                    <Box>
                        <Button
                            size="small"
                            onClick={() => {
                                navigator.clipboard.writeText(sessionLogs.join('\n'));
                                alert("Logs copied to clipboard!");
                            }}
                            sx={{ color: '#F36A2F', fontSize: '0.7rem', mr: 1 }}
                        >
                            Copy
                        </Button>
                        <Button
                            size="small"
                            onClick={() => setSessionLogs([])}
                            sx={{ color: '#ff4444', fontSize: '0.7rem', mr: 1 }}
                        >
                            Clear
                        </Button>
                        <IconButton
                            size="small"
                            onClick={() => setLogsOpen(false)}
                            sx={{ color: '#fff' }}
                        >
                            <CloseIcon sx={{ fontSize: '1.2rem' }} />
                        </IconButton>
                    </Box>
                </DialogTitle>
                <DialogContent sx={{ p: 0, bgcolor: '#000' }}>
                    <Box
                        sx={{
                            p: 2,
                            fontFamily: 'monospace',
                            fontSize: '0.75rem',
                            display: 'flex',
                            flexDirection: 'column',
                            gap: 0.5,
                            maxHeight: '100%',
                            overflowY: 'auto',
                            '&::-webkit-scrollbar': { width: '6px' },
                            '&::-webkit-scrollbar-thumb': { bgcolor: '#333', borderRadius: '3px' }
                        }}
                    >
                        {sessionLogs.length === 0 ? (
                            <Typography sx={{ color: '#444', textAlign: 'center', mt: 4 }}>No logs in this session.</Typography>
                        ) : (
                            sessionLogs.map((log, idx) => (
                                <Box key={idx} sx={{ borderBottom: '1px solid #111', pb: 0.5 }}>
                                    <span style={{ color: '#F36A2F', fontWeight: 600 }}>{log.split(']')[0]}]</span>
                                    <span style={{ color: '#ccc' }}>{log.split(']')[1]}</span>
                                </Box>
                            ))
                        )}
                        {/* Auto-scroll anchor */}
                        <div ref={el => { if (el) el.scrollIntoView({ behavior: 'smooth' }); }} />
                    </Box>
                </DialogContent>
            </Dialog>

            {/* Full JSON Modal */}
            <Dialog
                open={jsonModal.open}
                onClose={() => setJsonModal({ ...jsonModal, open: false })}
                fullWidth
                maxWidth="md"
                PaperProps={{
                    sx: { borderRadius: 3, bgcolor: '#fbfbfb' }
                }}
            >
                <DialogTitle sx={{ fontWeight: 800, color: '#333', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    {jsonModal.title}
                    <IconButton onClick={() => setJsonModal({ ...jsonModal, open: false })}>
                        <CloseIcon />
                    </IconButton>
                </DialogTitle>
                <DialogContent dividers>
                    <Box sx={{
                        bgcolor: '#1e1e1e',
                        color: '#d4d4d4',
                        p: 2,
                        borderRadius: 2,
                        fontFamily: 'monospace',
                        fontSize: '0.85rem',
                        whiteSpace: 'pre-wrap',
                        boxShadow: 'inset 0 2px 10px rgba(0,0,0,0.5)'
                    }}>
                        {JSON.stringify(jsonModal.data, null, 4)}
                    </Box>
                </DialogContent>
                <DialogActions sx={{ p: 2 }}>
                    <Button
                        onClick={() => {
                            navigator.clipboard.writeText(JSON.stringify(jsonModal.data, null, 2));
                        }}
                        sx={{ textTransform: 'none', color: '#F36A2F' }}
                    >
                        Copy JSON
                    </Button>
                    <Button onClick={() => setJsonModal({ ...jsonModal, open: false })} sx={{ textTransform: 'none', color: '#666' }}>
                        Close
                    </Button>
                </DialogActions>
            </Dialog>
        </Box >
    );
};

export default Chat;

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { getChatHistory } from '../api';
import { Box, Typography, Card, CardContent, Divider, Chip, Accordion, AccordionSummary, AccordionDetails, Button, CircularProgress } from '@mui/material';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';
// import Header from '../components/header';
import HistoryIcon from '@mui/icons-material/History';
import QuestionAnswerIcon from '@mui/icons-material/QuestionAnswer';
import SmartToyIcon from '@mui/icons-material/SmartToy';
import PersonIcon from '@mui/icons-material/Person';
import AddCommentIcon from '@mui/icons-material/AddComment';
import dayjs from 'dayjs';
import relativeTime from 'dayjs/plugin/relativeTime';
import Subheader from '../components/subheader';

dayjs.extend(relativeTime);

const ChatHistory = () => {
    const navigate = useNavigate();
    const [sessions, setSessions] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        const fetchHistory = async () => {
            const mobile = localStorage.getItem('mobile');
            if (!mobile) {
                navigate('/');
                return;
            }

            try {
                const res = await getChatHistory(mobile);
                if (res.data && res.data.sessions) {
                    setSessions(res.data.sessions);
                }
            } catch (err) {
                console.error("Failed to fetch history:", err);
                setError('Failed to load chat history.');
            } finally {
                setLoading(false);
            }
        };

        fetchHistory();
    }, [navigate]);

    const getRoleLabel = (msg) => {
        const role = msg.role || 'user';
        const assistant = msg.assistant || '';

        if (role === 'user') {
            return { label: 'You', color: 'default', icon: <PersonIcon fontSize="small" /> };
        }

        if (assistant === 'maya' || role === 'maya') {
            return { label: 'Maya', color: 'warning', icon: <SmartToyIcon fontSize="small" /> };
        }

        if (assistant === 'guruji' || role === 'guruji') {
            return { label: 'Guruji', color: 'primary', icon: <img src="/svg/guruji_illustrated.svg" style={{ width: 16, height: 16 }} alt="G" /> };
        }

        return { label: role, color: 'default', icon: null };
    };

    const formatContent = (content, msg) => {
        if (!content) return "";

        // Try to parse if it's Guruji and looks like JSON
        const isGuruji = msg?.role === 'guruji' || msg?.assistant === 'guruji';
        if (isGuruji && typeof content === 'string' && content.trim().startsWith('{')) {
            try {
                const data = JSON.parse(content.trim());
                const parts = [];
                Object.keys(data).filter(k => k.startsWith('para')).sort().forEach(k => {
                    parts.push(...data[k].split('#').map(s => s.trim()).filter(s => s !== ''));
                });

                if (data.follow_up || data.followup) {
                    parts.push(`<br>🤔 <b>${data.follow_up || data.followup}</b>`);
                }
                if (parts.length > 0) return parts.join("<br><br>");
            } catch (e) {
                // Ignore parsing errors and fallback
            }
        }

        // Also check if guruji_json or gurujiJson exists as an object
        const gJson = msg?.guruji_json || msg?.gurujiJson;
        if (gJson && typeof gJson === 'object') {
            const parts = [];
            Object.keys(gJson).filter(k => k.startsWith('para')).sort().forEach(k => {
                parts.push(...gJson[k].split('#').map(s => s.trim()).filter(s => s !== ''));
            });

            if (gJson.follow_up || gJson.followup) {
                parts.push(`<br>🤔 <b>${gJson.follow_up || gJson.followup}</b>`);
            }
            if (parts.length > 0) return parts.join("<br><br>");
        }

        return content;
    };

    return (
        <Box sx={{
            height: '100vh',
            display: 'flex',
            flexDirection: 'column',
            bgcolor: '#F9FAFB',
            overflow: 'hidden',
            "&::-webkit-scrollbar": {
                display: "none",
            },
            scrollbarWidth: "none",
        }}>
            {/* <Header /> */}
            <Subheader title={'History'} showBack onBack={() => navigate('/chat')} />

            <Box sx={{
                flex: 1,
                p: { xs: 2, sm: 3 },
                maxWidth: 'md',
                mx: 'auto',
                width: '100%',
                overflowY: 'auto',
                pb: 10 // Extra padding at bottom for better scroll feel
            }}>
                <Box sx={{ textAlign: 'center', mb: 3 }}>
                    <Typography variant="h5" sx={{ fontWeight: 700, color: '#111', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 1 }}>
                        <HistoryIcon sx={{ color: '#F26A2E' }} /> Consultation History
                    </Typography>
                    <Typography variant="body2" sx={{ color: '#666' }}>
                        Browse your past spiritual journeys with Guruji
                    </Typography>
                </Box>

                <Box sx={{ mb: 3, display: 'flex', justifyContent: 'center' }}>
                    <Button
                        variant="contained"
                        startIcon={<AddCommentIcon />}
                        onClick={() => navigate('/chat', { state: { newSession: true } })}
                        sx={{
                            bgcolor: '#F26A2E',
                            color: 'white',
                            borderRadius: '30px',
                            px: 4,
                            py: 1.5,
                            fontWeight: 700,
                            textTransform: 'none',
                            boxShadow: '0 8px 20px rgba(242, 106, 46, 0.2)',
                            '&:hover': {
                                bgcolor: '#d95a23',
                                boxShadow: '0 10px 25px rgba(242, 106, 46, 0.3)',
                            }
                        }}
                    >
                        Start New Consultation
                    </Button>
                </Box>

                {loading ? (
                    <Box sx={{ display: 'flex', justifyContent: 'center', py: 5 }}>
                        <div className="spinner spinner-indigo" style={{ width: 40, height: 40 }} />
                    </Box>
                ) : error ? (
                    <Typography color="error" textAlign="center">{error}</Typography>
                ) : sessions.length === 0 ? (
                    <Box sx={{ textAlign: 'center', py: 5, color: '#888' }}>
                        <QuestionAnswerIcon sx={{ fontSize: 48, mb: 2, opacity: 0.5 }} />
                        <Typography>No consultation history found.</Typography>
                    </Box>
                ) : (
                    <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
                        {sessions.map((session, sIndex) => (
                            <Accordion
                                key={session.session_id}
                                sx={{
                                    borderRadius: '12px !important',
                                    '&:before': { display: 'none' },
                                    boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
                                    overflow: 'hidden'
                                }}
                            >
                                <AccordionSummary
                                    expandIcon={<ExpandMoreIcon />}
                                    sx={{ bgcolor: '#fff', '&.Mui-expanded': { borderBottom: '1px solid #eee' } }}
                                >
                                    <Box sx={{ display: 'flex', flexDirection: 'column', textAlign: 'left' }}>
                                        <Typography sx={{ fontWeight: 700, color: '#F26A2E', fontSize: '0.9rem' }}>
                                            {session.topic}
                                        </Typography>
                                        <Typography variant="caption" sx={{ color: '#999' }}>
                                            {dayjs.unix(session.timestamp).format('DD MMM YYYY, hh:mm A')} ({dayjs.unix(session.timestamp).fromNow()})
                                        </Typography>
                                    </Box>
                                </AccordionSummary>
                                <AccordionDetails sx={{ bgcolor: '#fafafa', p: 2 }}>
                                    <Box sx={{
                                        display: 'flex',
                                        flexDirection: 'column',
                                        gap: 2,
                                        maxHeight: 400,
                                        overflowY: 'auto',
                                        pr: 1 // Padding for scrollbar
                                    }}>
                                        {session.messages.map((msg, mIndex) => {
                                            const { label, color, icon } = getRoleLabel(msg);
                                            const isUser = msg.role === 'user';

                                            if ((msg.assistant === 'maya' || msg.role === 'maya') && (!msg.content || msg.content.trim() === '')) {
                                                return null;
                                            }

                                            if (msg.assistant === 'maya' || msg.role === 'maya') {
                                                return (
                                                    <Box key={mIndex} sx={{ pt: 4, pb: 3, width: "100%", display: 'flex', justifyContent: 'center' }}>
                                                        <Box sx={{
                                                            position: "relative",
                                                            borderRadius: 2,
                                                            p: 2,
                                                            bgcolor: "#fece8d",
                                                            border: "none",
                                                            boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
                                                            width: '100%',
                                                        }}>
                                                            <Box sx={{
                                                                position: "absolute", top: -33, left: "50%", transform: "translateX(-50%)",
                                                                width: 50, height: 50, borderRadius: "50%", border: "3px solid #F36A2F",
                                                                bgcolor: "#fff", display: "flex", alignItems: "center", justifyContent: "center",
                                                            }}>
                                                                <img src="/svg/maya.png" style={{ width: 50 }} alt="Maya" />
                                                            </Box>
                                                            <Typography sx={{ fontSize: '0.95rem', lineHeight: 1.5, color: '#333', mt: 2, mb: 1.5, textAlign: 'left', fontWeight: 500, whiteSpace: 'pre-line' }}>
                                                                {msg.content}
                                                            </Typography>
                                                            {msg.timestamp && (
                                                                <Typography sx={{ fontSize: '0.75rem', opacity: 0.8, position: 'absolute', bottom: 6, right: 12, color: "#666", fontWeight: 500 }}>
                                                                    {dayjs(msg.timestamp).isValid()
                                                                        ? (msg.timestamp < 10000000000
                                                                            ? dayjs.unix(msg.timestamp).format('hh:mm A')
                                                                            : dayjs(msg.timestamp).format('hh:mm A'))
                                                                        : ''}
                                                                </Typography>
                                                            )}
                                                        </Box>
                                                    </Box>
                                                );
                                            }

                                            return (
                                                <Box key={mIndex} sx={{ display: 'flex', flexDirection: 'column', alignItems: isUser ? 'flex-end' : 'flex-start' }}>
                                                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 0.5 }}>
                                                        <Typography variant="caption" sx={{ fontWeight: 600, color: '#666' }}>{label}</Typography>
                                                        {icon}
                                                    </Box>
                                                    <Box
                                                        className="chat-bubble"
                                                        sx={{
                                                            maxWidth: '95%',
                                                            bgcolor: isUser ? '#2f3148' : '#ff8338',
                                                            color: isUser || (msg.assistant === 'guruji' || msg.role === 'guruji') ? '#fff' : '#333',
                                                            p: 1.5,
                                                            borderRadius: isUser ? '16px 16px 0 16px' : '16px 16px 16px 0',
                                                            boxShadow: '0 1px 4px rgba(0,0,0,0.05)',
                                                            border: isUser ? 'none' : '1px solid rgba(0,0,0,0.05)'
                                                        }}
                                                    >
                                                        <Typography variant="body2" dangerouslySetInnerHTML={{ __html: formatContent(msg.content, msg) }} />
                                                    </Box>
                                                </Box>
                                            );
                                        })}
                                    </Box>
                                </AccordionDetails>
                            </Accordion>
                        ))}
                    </Box>
                )}
            </Box>
        </Box>
    );
};

export default ChatHistory;

import React, { useState, useEffect } from "react";
import {
    Box,
    Typography,
    Drawer,
    InputBase,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
// import ArrowBackIcon from '@mui/icons-material/ArrowBack';
import CurrencyRupeeIcon from '@mui/icons-material/CurrencyRupee';
import Header from "../components/header";
import GurujiImage from "../components/gurujiImg";
import PrimaryButton from "../components/PrimaryButton";

const Dakshina = ({ open, onClose, onSuccess }) => {
    const navigate = useNavigate();
    const [amount, setAmount] = useState("");
    const [paymentEnabled, setPaymentEnabled] = useState(true);
    const [loading, setLoading] = useState(false);
    const mobile = localStorage.getItem('mobile');
    const referenceid = localStorage.getItem('currentProfileId');
    const userName = localStorage.getItem('userName') || 'User';

    useEffect(() => {
        // Only run if not explicitly closed in drawer mode
        if (open !== false) {
            checkPaymentStatus();
            const script = document.createElement('script');
            script.src = 'https://checkout.razorpay.com/v1/checkout.js';
            script.async = true;
            document.body.appendChild(script);
            return () => {
                if (document.body.contains(script)) {
                    document.body.removeChild(script);
                }
            };
        }
    }, [open]);

    const checkPaymentStatus = async () => {
        try {
            const { getSystemSettings } = await import('../api');
            const { data } = await getSystemSettings();
            if (data && typeof data.payment_enabled !== 'undefined') {
                setPaymentEnabled(data.payment_enabled);
            }
        } catch (e) {
            console.error("Failed to check payment status", e);
        }
    };

    const handleAmountSelect = (val) => {
        setAmount(val);
    };

    const handleProceed = async () => {
        if (!amount || isNaN(amount) || Number(amount) <= 0) {
            alert("Please enter a valid amount.");
            return;
        }

        if (!paymentEnabled) {
            alert("Payments are currently disabled by the administrator.");
            return;
        }

        setLoading(true);
        try {
            const { createPaymentOrder, verifyPayment } = await import('../api');

            // 1. Create Order
            const orderRes = await createPaymentOrder(parseFloat(amount), mobile, referenceid);
            const order = orderRes.data;

            // 2. Open Razorpay
            const options = {
                key: order.key,
                amount: order.amount,
                currency: order.currency,
                name: "Astrology Guruji",
                description: "Dakshina Contribution",
                order_id: order.order_id,
                handler: async function (response) {
                    try {
                        // 3. Verify Payment
                        await verifyPayment({
                            razorpay_order_id: response.razorpay_order_id,
                            razorpay_payment_id: response.razorpay_payment_id,
                            razorpay_signature: response.razorpay_signature
                        });
                        // alert("Dakshina received with gratitude! 🙏");
                        if (onClose) onClose();
                        if (onSuccess) {
                            // onSuccess(amount);
                            onSuccess(amount, response);
                        } else {
                            navigate('/chat', { state: { newSession: true } });
                        }
                    } catch (err) {
                        console.error("Verification failed", err);
                        alert("Payment verification failed. Please contact support.");
                    }
                },
                prefill: {
                    contact: mobile,
                },
                theme: {
                    color: "#F36A2F"
                }
            };

            if (window.Razorpay) {
                const rzp = new window.Razorpay(options);
                rzp.on('payment.failed', function (response) {
                    alert("Payment Failed: " + response.error.description);
                });
                rzp.open();
            } else {
                alert("Payment gateway not loaded. Please refresh.");
            }

        } catch (error) {
            console.error("Payment init failed:", error);
            alert("Failed to initiate payment. Please try again.");
        } finally {
            setLoading(false);
        }
    };

    const content = (
        <Box sx={{ p: 3, flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', bgcolor: open ? '#fff4e5' : '#FFF6EB', minHeight: open ? 'auto' : '100vh' }}>

            <Box sx={{ width: '100%', maxWidth: 400 }}>
                {/* {!open && (
                    <IconButton onClick={() => navigate('/chat')} sx={{ mb: 2, color: '#F36A2F' }}>
                        <ArrowBackIcon />
                    </IconButton>
                )} */}

                <Box sx={{ textAlign: 'center', mb: 3 }}>
                    <GurujiImage sx={{ mb: 1, width: 120, mx: 'auto' }} />
                    <Typography sx={{ mb: 1, fontSize: 16 }}>
                        {userName}, let there be happiness in your life!
                    </Typography>
                </Box>

                <Typography sx={{ fontWeight: 500, color: '#dc5d35', mb: 0, textAlign: 'center', fontSize: '1.3rem' }}>
                    Dakshina
                </Typography>

                {!paymentEnabled && (
                    <Box sx={{ mb: 2, p: 1.5, bgcolor: '#FFEBEE', color: '#D32F2F', borderRadius: 2, fontSize: '0.85rem', fontWeight: 700 }}>
                        ⚠️ Online payments are currently paused.
                    </Box>
                )}
                <Box sx={{ mb: 3, border: '2px solid #f26531', borderRadius: 2, p: 2, bgcolor: '#fcebd3', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                    <Box sx={{ textAlign: 'left', color: '#000', }}>
                        <Typography variant="body2" sx={{ mb: 2 }}>
                            Our astrology and astrologer services are supported by the 'Dakshina' given by people like you.
                        </Typography>
                        <Typography variant="body2" sx={{ mb: 2 }}>
                            You may give Guruji a Dakshina of your choice.
                        </Typography>
                    </Box>

                    <Box sx={{ display: 'flex', alignItems: 'center', mb: 3, justifyContent: 'center' }}>
                        <CurrencyRupeeIcon sx={{ color: "#707070", ml: 1 }} />
                        <InputBase
                            fullWidth
                            placeholder="Enter amount"
                            value={amount}
                            onChange={(e) => setAmount(e.target.value)}
                            type="number"
                            sx={{
                                px: 1,
                                fontWeight: 500,
                                fontSize: '1rem',
                                width: '60%',
                                bgcolor: 'white',
                                borderRadius: 1,
                                p: 1,
                                border: 'none',
                                '& input::-webkit-outer-spin-button, & input::-webkit-inner-spin-button': {
                                    WebkitAppearance: 'none',
                                    margin: 0,
                                },
                                '& input[type=number]': {
                                    MozAppearance: 'textfield',
                                },
                            }}
                        />
                    </Box>

                    <PrimaryButton
                        label={loading ? "Processing..." : "Give Dakshina to Guruji"}
                        fullWidth
                        onClick={handleProceed}
                        // disabled={loading || !paymentEnabled || !amount}
                        sx={{
                            bgcolor: '#54a170',
                            color: '#fff',
                            borderRadius: 50,
                            textTransform: 'none',
                            fontWeight: 500,
                            p: .8,
                            px: 4,
                            width: 'auto',
                            '&:hover': { bgcolor: '#458a5c' }
                        }}
                    />


                </Box>

                {open && (
                    <PrimaryButton
                        label='Close'
                        fullWidth
                        onClick={onClose}
                        sx={{
                            color: "#b4b4b4",
                            py: 1,
                            px: 5,
                            borderRadius: 10,
                            fontSize: "0.9rem",
                            textTransform: "none",
                            bgcolor: '#fff',
                            boxShadow: 'none',
                            margin: 'auto',
                            width: 'auto',
                            display: 'flex',
                            justifyContent: 'center'
                        }}
                    />


                )}
            </Box>
        </Box>
    );

    if (open !== undefined) {
        return (
            <Drawer
                anchor="bottom"
                open={open}
                onClose={onClose}
                ModalProps={{ keepMounted: true }}
                sx={{
                    "& .MuiDrawer-paper": {
                        bgcolor: "#fff4e5",
                        borderTopLeftRadius: 35,
                        borderTopRightRadius: 35,
                        maxWidth: 450,
                        width: "100%",
                        mx: "auto",
                        overflow: 'hidden'
                    },
                }}
            >
                {content}
            </Drawer>
        );
    }

    return (
        <Box sx={{
            minHeight: '100vh',
            display: 'flex',
            flexDirection: 'column',
            bgcolor: '#FFF6EB',
        }}>
            <Header backgroundImage="/svg/top_curve_dark.svg" />
            {content}
        </Box>
    );
};

