            }}
        >
            <Header />
            <HamburgerMenu
                menubarsx={{
                    position: 'fixed',
                    // top: 25,
                    transition: 'transform 0.3s ease-in-out',
                    // transform: showHeader ? 'translateY(0)' : 'translateY(-100px)',
                    zIndex: 1210,
                    pointerEvents: showHeader ? 'auto' : 'none',
                }}
            />

            <Box sx={{ width: "100%", px: 3, py: 4, mt: 18 }}>
