                        '&:hover': { color: '#F05A28' }
                    }} 
                    onClick={handleBack}
                >
                    &lt; Prev
                </Typography>

                <PrimaryButton
                    label="Get to know MAYA"
                    sx={{ p: 1.2, height: 48, borderRadius: 5, width: { xs: "70%", sm: "55%" } }}
                    onClick={() => navigate('/onboarding')}
                    endIcon={<KeyboardDoubleArrowRightIcon sx={{ fontSize: 24 }} />}
                />
            </Box>
        </Box>
    );
};

