import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { Box, Typography, Card, CardContent, Divider, Grid, MenuItem, TextField, Alert, Snackbar } from '@mui/material';
import KeyboardArrowDownRoundedIcon from '@mui/icons-material/KeyboardArrowDownRounded';
import Subheader from '../components/subheader';
import { updateProfile, getUserStatus } from '../api';

// import { InputField } from '../components/inputwithIcon';
import BirthDetailsForm from '../components/BirthDetailsForm';
import PrimaryButton from "../components/PrimaryButton";

const UserProfile = () => {
    const navigate = useNavigate();
    const [user, setUser] = useState(null); // Keep user for reference if needed, but details drives the form
    const [details, setDetails] = useState({
        name: '', mobile: '', relation: 'Self (This is me)', gender: 'Male', chart_style: 'South Indian', dob: '', tob: '', pob: '', current_city: '', email: '',
        country: '', state: '', region_dist: '', txt_place_search: '',
        longdeg: '', longmin: '', longdir: '', latdeg: '', latmin: '', latdir: '',
        timezone: '', timezone_name: '', latitude_google: '', longitude_google: '', correction: 0,
        referenceid: ''
    });
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [errors, setErrors] = useState({});
    const [focusTrigger, setFocusTrigger] = useState(0);
    const [saving, setSaving] = useState(false);
    const [successMsg, setSuccessMsg] = useState('');

    const formatDate = (dateString) => {
        if (!dateString) return '';
        if (/^\d{4}-\d{2}-\d{2}$/.test(dateString)) return dateString;
        const date = new Date(dateString);
        if (isNaN(date.getTime())) {
            const parts = dateString.split(/[-/]/);
            if (parts.length === 3) {
                return `${parts[2]}-${parts[1].padStart(2, '0')}-${parts[0].padStart(2, '0')}`;
            }
            return '';
        }
        return date.toISOString().split('T')[0];
    };

    const formatTime = (timeString) => {
        if (!timeString) return '';
        if (/^\d{2}:\d{2}$/.test(timeString)) return timeString;
        if (/^\d{2}:\d{2}:\d{2}$/.test(timeString)) return timeString.substring(0, 5);
        const date = new Date(`2000-01-01 ${timeString}`);
        if (!isNaN(date.getTime())) {
            return date.toTimeString().substring(0, 5);
        }
        return '';
    };

    useEffect(() => {
        const fetchProfile = async () => {
            const mobile = localStorage.getItem('mobile');
            if (!mobile) {
                navigate('/');
                return;
            }

            try {
                const res = await getUserStatus(mobile);
                if (res.data.user_profile) {
                    const profile = res.data.user_profile;
                    setUser(profile);
                    setDetails({
                        name: profile.name || '',
                        mobile: profile.mobile || localStorage.getItem('mobile') || '',
                        relation: profile.relation || 'Self (This is me)',
                        email: profile.email || '',
                        gender: profile.gender || 'Male',
                        dob: formatDate(profile.dob),
                        tob: formatTime(profile.tob),
                        pob: profile.pob || '',
                        current_city: profile.current_city || '',
                        chart_style: profile.chart_style || 'South Indian',
                        country: profile.country || 'India',
                        state: profile.state || '',
                        region_dist: profile.region_dist || '',
                        txt_place_search: profile.txt_place_search || '',
                        longdeg: profile.longdeg || '',
                        longmin: profile.longmin || '',
                        longdir: profile.longdir || '',
                        latdeg: profile.latdeg || '',
                        latmin: profile.latmin || '',
                        latdir: profile.latdir || '',
                        timezone: profile.timezone || '',
                        timezone_name: profile.timezone_name || '',
                        latitude_google: profile.latitude_google || '',
                        longitude_google: profile.longitude_google || '',
                        correction: profile.correction || 0,
                        referenceid: profile.referenceid || ''
                    });
                } else {
                    setError('Profile not found.');
                }
            } catch (err) {
                console.error("Failed to fetch profile:", err);
                setError('Failed to load profile. Please try again.');
            } finally {
                setLoading(false);
            }
        };

        fetchProfile();

        // Load scripts in sequence to ensure proper initialization
        // (Note: BirthDetailsForm has a polling mechanism that will pick up initAutocomplete 
        // once it becomes available on window)
        const jqueryScript = document.createElement('script');
        jqueryScript.src = 'https://cdn.jsdelivr.net/npm/jquery@3.7.1/dist/jquery.min.js';
        jqueryScript.onload = () => {
            const solarScript = document.createElement('script');
            solarScript.src = '/solar.js';
            solarScript.onload = () => {
                const capacScript = document.createElement('script');
                capacScript.src = 'https://placesapis.clickastro.com/capac/api/?key=AJSjkshjjSDkjhKDJDhjdjdklDldld&callback=initAutocomplete';
                document.body.appendChild(capacScript);
            };
            document.body.appendChild(solarScript);
        };
        document.body.appendChild(jqueryScript);

        return () => {
            const scriptsToRemove = [
                'https://cdn.jsdelivr.net/npm/jquery@3.7.1/dist/jquery.min.js',
                'https://placesapis.clickastro.com/capac/api/'
            ];
            scriptsToRemove.forEach(src => {
                const scripts = document.querySelectorAll(`script[src^="${src}"]`);
                scripts.forEach(script => {
                    if (document.body.contains(script)) {
                        document.body.removeChild(script);
                    }
                });
            });
            delete window.CAPACInitListener;
        };
    }, [navigate]);

    const handleSave = async () => {
        setSaving(true);
        setError('');
        setErrors({});

        // Validation
        const { name, email, dob, tob, pob, current_city, gender } = details;
        const newErrors = {};

        // Get location details from hidden inputs (populated by solar.js)
        const locationFields = {
            country: document.getElementById('country')?.value || '',
            state: document.getElementById('state')?.value || '',
            region_dist: document.getElementById('region_dist')?.value || '',
            txt_place_search: document.getElementById('txt_place_search')?.value || '',
            longdeg: document.getElementById('longdeg')?.value || '',
            longmin: document.getElementById('longmin')?.value || '',
            longdir: document.getElementById('longdir')?.value || '',
            latdeg: document.getElementById('latdeg')?.value || '',
            latmin: document.getElementById('latmin')?.value || '',
            latdir: document.getElementById('latdir')?.value || '',
            timezone: document.getElementById('timezone')?.value || '0',
            timezone_name: document.getElementById('timezone_name')?.value || '',
            latitude_google: document.getElementById('latitude_google')?.value || '',
            longitude_google: document.getElementById('longitude_google')?.value || '',
            correction: document.getElementById('correction')?.value || '0'
        };

        if (!name.trim()) newErrors.name = "Name is required.";
        if (!email.trim()) newErrors.email = "Email is required.";
        else if (!/\S+@\S+\.\S+/.test(email)) newErrors.email = "Email is invalid.";
        if (!gender.trim()) newErrors.gender = "Gender is required.";
        if (gender.trim() && !["Male", "Female"].includes(gender.trim())) newErrors.gender = "Gender must be Male or Female.";
        if (!dob.trim()) newErrors.dob = "Date of birth is required.";
        if (!tob.trim()) newErrors.tob = "Time of birth is required.";
        if (!pob.trim()) {
            newErrors.pob = "Place of birth is required.";
        } else if (!locationFields.longdeg || !locationFields.latdeg || locationFields.longdeg === '0' || locationFields.latdeg === '0') {
            newErrors.pob = "Please select a valid birth place from the suggestions dropdown.";
        }

        if (Object.keys(newErrors).length > 0) {
            setErrors(newErrors);
            setFocusTrigger(prev => prev + 1);
            setSaving(false);
            return;
        }

        try {

            const payload = { ...details, ...locationFields };
            await updateProfile(payload);
            setSuccessMsg("Profile updated successfully! Your report is being regenerated.");

            // Optional: Update local storage if name/email changed
            localStorage.setItem('userName', details.name);
            localStorage.setItem('userEmail', details.email);

        } catch (err) {
            console.error(err);
            setError(err.response?.data?.detail || "Failed to update profile.");
        } finally {
            setSaving(false);
        }
    };

    return (
        <Box sx={{
            height: '100vh',
            display: 'flex',
            flexDirection: 'column',
            bgcolor: '#FFF6EB',
            overflow: 'hidden'
        }}>
            <Box sx={{ position: 'relative', flexShrink: 0, zIndex: 100, bgcolor: '#FFF6EB' }}>
                <Subheader title="Edit Profile" showBack navTo="/chat" />
            </Box>

            <Box sx={{
                flex: 1,
                overflowY: 'auto',
                position: 'relative',
                zIndex: 10,
                mt: 9,
                px: 2,
                pb: 5,
                pt: 4,
                "&::-webkit-scrollbar": {
                    display: "none",
                },
                scrollbarWidth: "none",
            }}>


                {loading ? (
                    <Box sx={{ display: 'flex', justifyContent: 'center', py: 5 }}>
                        <div className="spinner-indigo" style={{ width: 40, height: 40 }} />
                    </Box>
                ) : (
                    <>
                        {/* <Box sx={{ width: '100%', display: 'flex', justifyContent: 'left', padding: '0 10px' }}>
                            <Box sx={{ width: { xs: "100%", sm: "90%" } }}>
                                <Typography
                                    sx={{
                                        color: "#dc5d35",
                                        fontWeight: 600,
                                        mb: 1,
                                        fontSize: 16,
                                    }}
                                >
                                    Relation:
                                </Typography>
                                <TextField
                                    select
                                    fullWidth
                                    value={details.relation || 'Self (This is me)'}
                                    onChange={(e) => setDetails({ ...details, relation: e.target.value })}
                                    variant="outlined"
                                    sx={{
                                        mb: 2,
                                        bgcolor: "#fff",
                                        borderRadius: 1,
                                        width: '75%',
                                        "& fieldset": { border: "none" },
                                        "& .MuiInputBase-root": { height: 52 },
                                        boxShadow: '0px 2px 4px rgba(0,0,0,0.05)',
                                        "& .MuiSelect-icon": {
                                            color: "#dc5d35",
                                            fontSize: 40,
                                            right: 12,
                                            fontWeight: 900,
                                        }
                                    }}
                                    SelectProps={{
                                        IconComponent: KeyboardArrowDownRoundedIcon,
                                    }}
                                >
                                    {['Self (This is me)', 'Mother', 'Father', 'Spouse', 'Son', 'Daughter', 'Brother', 'Sister', 'Friend', 'Other'].map((option) => (
                                        <MenuItem key={option} value={option}>
                                            {option}
                                        </MenuItem>
                                    ))}
                                </TextField>
                            </Box>
                        </Box> */}
                        <Box component="form" name="frmplaceorder" id="frmplaceorder" sx={{ width: '100%' }}>
                            <BirthDetailsForm details={details} setDetails={setDetails} error={error} errors={errors} setErrors={setErrors} focusTrigger={focusTrigger} />
                        </Box>
                        <Box sx={{ mt: 6, display: 'flex', justifyContent: 'right', width: '100%' }}>
                            <PrimaryButton
                                label={saving ? "Saving..." : "Save profile"}
                                onClick={handleSave}
                                disabled={saving}
                                sx={{
                                    bgcolor: "#dc5d35",
                                    color: "#fff",
                                    fontWeight: 500,
                                    fontSize: 16,
                                    textTransform: "none",
                                    px: 3,
                                    py: 1.5,
                                    borderRadius: 5,
                                    boxShadow: "0px 2px 4px rgba(0,0,0,0.05)",
                                    "&:hover": {
                                        bgcolor: "#c24c2f",
                                        boxShadow: "0px 4px 6px rgba(0,0,0,0.1)",
                                    },
                                }}
                            />
                        </Box>
                    </>
                )}
            </Box>

            <Snackbar
                open={!!successMsg}
                autoHideDuration={6000}
                onClose={() => setSuccessMsg('')}
                anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
            >
                <Alert onClose={() => setSuccessMsg('')} severity="success" sx={{ width: '80%', m: 'auto' }}>
                    {successMsg}
                </Alert>
            </Snackbar>

            <Snackbar
                open={!!error && !loading}
                autoHideDuration={6000}
                onClose={() => setError('')}
                anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
            >
                <Alert onClose={() => setError('')} severity="error" sx={{ width: '100%' }}>
                    {error}
                </Alert>
            </Snackbar>
        </Box>
    );
};

export default UserProfile;

import React, { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { sendOtp, verifyOtp, setAuthToken } from "../api";
import { Box, Typography } from "@mui/material";
import Header from "../components/header";
import PrimaryButton from "../components/PrimaryButton";
import GurujiImage from "../components/gurujiImg";

const Verify = () => {
  const navigate = useNavigate();
  const [otp, setOtp] = useState(["", "", "", ""]);
  const [mobile, setMobile] = useState("");
  const [loading, setLoading] = useState(false);
  const [resending, setResending] = useState(false);
  const [error, setError] = useState("");
  const [info, setInfo] = useState("");
  const inputRefs = useRef([]);

  useEffect(() => {
    const storedMobile = localStorage.getItem("mobile");
    if (!storedMobile) {
      navigate("/");
    } else {
      setMobile(storedMobile);
    }

    // Session timeout: 5 minutes = 300,000 ms
    const timeoutId = setTimeout(() => {
      console.log("Verify session expired. Redirecting...");
      navigate("/");
    }, 300000);

    return () => clearTimeout(timeoutId);
  }, [navigate]);

  const handleResendOtp = async () => {
    setResending(true);
    setError("");
    setInfo("");
    try {
      const res = await sendOtp(mobile);
      setInfo(`OTP Resent!`);
    } catch (err) {
      const msg =
        err.response?.data?.detail || err.message || "Failed to resend OTP.";
      setError(`Resend failed: ${msg}`);
    } finally {
      setResending(false);
    }
  };

  const handleOtpChange = (index, value) => {
    // Only allow digits
    if (value && !/^\d$/.test(value)) return;

    const newOtp = [...otp];
    newOtp[index] = value;
    setOtp(newOtp);

    // Auto-focus next input
    if (value && index < 3) {
      inputRefs.current[index + 1]?.focus();
    }
  };

  const handleKeyDown = (index, e) => {
    // Handle backspace
    if (e.key === "Backspace") {
      if (!otp[index] && index > 0) {
        inputRefs.current[index - 1]?.focus();
        const newOtp = [...otp];
        newOtp[index - 1] = "";
        setOtp(newOtp);
      } else if (otp[index]) {
        const newOtp = [...otp];
        newOtp[index] = "";
        setOtp(newOtp);
      }
    }
  };

  const handlePaste = (e) => {
    e.preventDefault();
    const pastedData = e.clipboardData
      .getData("text")
      .replace(/\D/g, "")
      .slice(0, 4);
    if (pastedData) {
      const newOtp = pastedData.split("").concat(["", "", "", ""]).slice(0, 4);
      setOtp(newOtp);
      const nextIndex = Math.min(pastedData.length, 3);
      inputRefs.current[nextIndex]?.focus();
    }
  };

  const handleOtpSubmit = async (e) => {
    if (e) e.preventDefault();
    const otpString = otp.join("");
    if (otpString.length !== 4) {
      setError("Please enter all 4 digits");
      return;
    }

    setLoading(true);
    setError("");
    setInfo("");
    try {
      const res = await verifyOtp(mobile, otpString);
      const { access_token, is_new_user, user_profiles, default_profile_id } = res.data;

      setAuthToken(access_token);
      localStorage.setItem("mobile", mobile);
      localStorage.setItem("token", access_token);

      if (user_profiles && user_profiles.length > 0) {
        // Find the default profile or fallback to the first one
        const defaultProfile = user_profiles.find(p => p.referenceid === default_profile_id) || user_profiles[0];
        localStorage.setItem("userName", defaultProfile.name || "");
        localStorage.setItem("userEmail", defaultProfile.email || "");
        localStorage.setItem("currentProfileId", defaultProfile.referenceid);
      }

      if (is_new_user) {
        navigate("/register");
      } else {
        navigate("/chat");
      }
    } catch (err) {
      console.error("Verification error:", err);
      const msg = err.response?.data?.detail;
      const errorMsg = Array.isArray(msg) ? msg[0].msg : msg || "Invalid OTP.";
      setError(errorMsg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <Header />
      <Box
        sx={{
          flex: 1,
          display: "flex",
          flexDirection: "column",
          justifyContent: "center",
          alignItems: "center",
          textAlign: "center",
          px: 3,
          pb: 1,
          mt: 18,
        }}
      >
        <Box textAlign="center">
          <Typography fontSize={16} mt={1} mb={1} sx={{ fontFamily: "'Century Gothic', sans-serif" }}>
            Welcome to{" "}
            <Typography component="span" fontWeight={600} color="#dc5d35">
              Findastro
            </Typography>
            !
          </Typography>

          <GurujiImage />
        </Box>

        {/* OTP Section */}
        <Box
          sx={{
            mt: 4,
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            width: "100%",
            px: 2,
            mb: 2,
          }}
        >
          <Typography
            sx={{
              mb: 1,
              color: "#dc5d35",
              fontWeight: 600,
              fontSize: "1rem",
            }}
          >
            Enter OTP
          </Typography>

          {/* OTP Inputs */}
          <Box sx={{ display: "flex", gap: { xs: 1.5, sm: 3 }, mb: 0 }}>
            {otp.map((value, index) => (
              <input
                key={index}
                ref={(el) => (inputRefs.current[index] = el)}
                value={value}
                onChange={(e) => handleOtpChange(index, e.target.value)}
                onKeyDown={(e) => handleKeyDown(index, e)}
                onPaste={handlePaste}
                maxLength={1}
                inputMode="numeric"
                autoComplete="one-time-code"
                style={{
                  width: "min(65px, 18vw)",
                  height: "min(60px, 20vw)",
                  textAlign: "center",
                  fontSize: "min(24px, 6vw)",
                  borderRadius: 8,
                  border: "none",
                  outline: "none",
                  boxShadow: "0 -6px 12px rgba(0, 0, 0, 0.15)",
                  backgroundColor: "#fff",
                }}
              />
            ))}
          </Box>
          {error && (
            <Typography color="error" variant="body2" sx={{ mt: 1 }}>
              {error}
            </Typography>
          )}
          {info && (
            <Typography color="success.main" variant="body2" sx={{ mt: 1 }}>
              {info}
            </Typography>
          )}

          {/* Resend */}
          <Box
            sx={{
              width: "100%",
              display: "flex",
              justifyContent: "flex-end",
              mb: 1,
            }}
          >
            <Typography
              sx={{
                color: "#dc5d35",
                fontWeight: 600,
                cursor: "pointer",
                mr: { xs: 0, sm: 3 },
                fontSize: 14,
                mt: 1,
              }}
              onClick={handleResendOtp}
            >
              {resending ? "Resending..." : "Resend OTP"}
            </Typography>
          </Box>

          <PrimaryButton
            label={loading ? "Verifying..." : "Continue"}
            onClick={handleOtpSubmit}
            disabled={loading || resending}
          />
        </Box>
      </Box>
    </>
  );
};

export default Verify;

import React, { useState, useEffect } from 'react';
import DashboardOverview from './DashboardOverview';
import SystemPromptEditor from './SystemPromptEditor';
import EditMayaPrompt from './EditMayaPrompt';
import ReportPromptEditor from './ReportPromptEditor';
import PsycologyPromptEditor from './PsycologyPromptEditor';
import LoginLogs from './LoginLogs';
import MonetizationRules from './MonetizationRules';
import RechargeConfigManager from './RechargeConfigManager';
import {
    getAllUsers as getUsers,
    getUserDetails,
    getBalance as getUserWallet,
    getTransactionHistory as getUserTransactions,
    toggleWalletSystem,
    getSubscriptionPlans,
    toggleUserSubscription,
    updateUserProfile
} from '../../api';

const NavButton = ({ active, onClick, icon, label, themeColor }) => {
