                                <div className="p-4 border-t border-slate-800">
                                    <div className="flex space-x-2">
                                        <input type="text" value={testInput} onChange={(e) => setTestInput(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleTestChat()} placeholder="Inquire document context..." disabled={testStatus !== 'ready'} className="flex-1 bg-slate-900 border border-slate-800 rounded-xl px-4 py-3 text-sm text-white outline-none focus:ring-2 focus:ring-indigo-500 disabled:opacity-50 placeholder-slate-600" />
                                        <button onClick={handleTestChat} disabled={testStatus !== 'ready' || !testInput.trim()} className={`p-3 rounded-xl transition-all ${testStatus === 'ready' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/40' : 'bg-slate-800 text-slate-600'}`}><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg></button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                ) : null}
            </main>

            <style>{`
                .custom-scrollbar::-webkit-scrollbar { width: 8px; }
                .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 20px; }
                .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #475569; }
            `}</style>
        </div>
    );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { getLoginLogs } from '../../api';

const LoginLogs = () => {
    const [logs, setLogs] = useState([]);
    const [loading, setLoading] = useState(true);
    const [filters, setFilters] = useState({
        name: '',
        email: '',
        mobile: '',
        date: ''
    });

    useEffect(() => {
        fetchLogs();
    }, []);

    const fetchLogs = async (currentFilters = filters) => {
        setLoading(true);
        try {
            const response = await getLoginLogs(currentFilters);
            setLogs(response.data || response);
        } catch (err) {
            console.error("Failed to fetch logs", err);
        } finally {
            setLoading(false);
        }
    };

    const handleFilterChange = (e) => {
        const { name, value } = e.target;
        const newFilters = { ...filters, [name]: value };
        setFilters(newFilters);
    };

    const applyFilters = () => {
        fetchLogs(filters);
    };

    const clearFilters = () => {
        const cleared = { name: '', email: '', mobile: '', date: '' };
        setFilters(cleared);
        fetchLogs(cleared);
    };

    const formatDate = (timestamp) => {
        if (!timestamp) return 'N/A';
        const date = new Date(timestamp * 1000);
        return date.toLocaleString();
    };

    return (
        <div className="p-8 space-y-8 max-w-7xl mx-auto bg-black animate-in fade-in duration-500">
            <div className="flex flex-col md:flex-row md:items-end justify-between space-y-4 md:space-y-0">
                <h2 className="text-4xl font-black text-white tracking-tighter">Login Logs</h2>
                <div className="flex space-x-2">
                    <button
                        onClick={applyFilters}
                        className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl text-xs font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-900/40"
                    >
                        Apply Filters
                    </button>
                    <button
                        onClick={clearFilters}
                        className="px-6 py-2.5 bg-slate-800 text-slate-400 rounded-xl text-xs font-black uppercase tracking-widest hover:bg-slate-700 transition-all"
                    >
                        Clear
                    </button>
                </div>
            </div>

            {/* Filters bar */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4 bg-slate-900/50 p-6 rounded-3xl border border-slate-800/60 transition-all">
                <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Name</label>
                    <input
                        type="text"
                        name="name"
                        value={filters.name}
                        onChange={handleFilterChange}
                        placeholder="Filter by name"
                        className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-2 text-xs text-white outline-none focus:ring-2 focus:ring-indigo-500 placeholder-slate-600"
                    />
                </div>
                <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Email</label>
                    <input
                        type="text"
                        name="email"
                        value={filters.email}
                        onChange={handleFilterChange}
                        placeholder="Filter by email"
                        className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-2 text-xs text-white outline-none focus:ring-2 focus:ring-indigo-500 placeholder-slate-600"
                    />
                </div>
                <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Phone</label>
                    <input
                        type="text"
                        name="mobile"
                        value={filters.mobile}
                        onChange={handleFilterChange}
                        placeholder="Filter by phone"
                        className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-2 text-xs text-white outline-none focus:ring-2 focus:ring-indigo-500 placeholder-slate-600"
                    />
                </div>
                <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Date</label>
                    <input
                        type="date"
                        name="date"
                        value={filters.date}
                        onChange={handleFilterChange}
                        className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-2 text-xs text-white outline-none focus:ring-2 focus:ring-indigo-500 [color-scheme:dark]"
                    />
                </div>
            </div>

            {/* Logs Table */}
            <div className="bg-slate-900/40 rounded-[2.5rem] border border-slate-800/60 shadow-2xl overflow-hidden backdrop-blur-sm">
                <div className="overflow-x-auto custom-scrollbar">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-slate-800/50 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">
                                <th className="px-8 py-5">Date & Time</th>
                                <th className="px-8 py-5">User Details</th>
                                <th className="px-8 py-5">Method</th>
                                <th className="px-8 py-5">Status</th>
                                <th className="px-8 py-5">Network Info</th>
                                <th className="px-8 py-5 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-800/40">
                            {loading ? (
                                <tr>
                                    <td colSpan="6" className="px-8 py-20 text-center">
                                        <div className="flex flex-col items-center space-y-4">
                                            <div className="w-10 h-10 border-4 border-slate-800 border-t-indigo-500 rounded-full animate-spin"></div>
                                            <p className="text-slate-600 font-black uppercase tracking-widest text-[10px]">Retrieving Audit Trail</p>
                                        </div>
                                    </td>
                                </tr>
                            ) : logs.length === 0 ? (
                                <tr>
                                    <td colSpan="6" className="px-8 py-20 text-center">
                                        <p className="text-slate-700 font-black uppercase tracking-widest text-xs">No logs found</p>
                                    </td>
                                </tr>
                            ) : (
                                logs.map((log, i) => (
                                    <tr key={i} className="hover:bg-slate-800/20 transition-colors group">
                                        <td className="px-8 py-6">
                                            <p className="text-sm font-black text-white">{formatDate(log.timestamp).split(',')[0]}</p>
                                            <p className="text-[10px] font-bold text-slate-500">{formatDate(log.timestamp).split(',')[1]}</p>
                                        </td>
                                        <td className="px-8 py-6">
                                            <div className="flex items-center space-x-3">
                                                <div className="w-10 h-10 rounded-xl bg-slate-800 flex items-center justify-center font-black text-slate-400 group-hover:bg-indigo-600 group-hover:text-white transition-all">
                                                    {log.name ? log.name[0].toUpperCase() : (log.mobile ? log.mobile[log.mobile.length - 1] : '?')}
                                                </div>
                                                <div>
                                                    <p className="text-sm font-black text-slate-200">{log.name || 'Anonymous'}</p>
                                                    <p className="text-[10px] font-bold text-slate-500">{log.mobile} • {log.email || 'No email'}</p>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-8 py-6">
                                            <span className="px-2.5 py-1 rounded-lg bg-slate-800 text-[10px] font-black uppercase tracking-tighter text-slate-400 border border-slate-700">
                                                {log.method.replace('_', ' ')}
                                            </span>
                                        </td>
                                        <td className="px-8 py-6">
                                            <div className="flex items-center space-x-2">
                                                <div className={`w-1.5 h-1.5 rounded-full ${log.status === 'success' ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]' : 'bg-rose-500 shadow-[0_0_8px_rgba(244,63,94,0.5)]'}`}></div>
                                                <span className={`text-[10px] font-black uppercase tracking-widest ${log.status === 'success' ? 'text-emerald-400' : 'text-rose-400'}`}>
                                                    {log.status}
                                                </span>
                                            </div>
                                        </td>
                                        <td className="px-8 py-6">
                                            <p className="text-[10px] font-mono text-slate-400">{log.ip_address || 'Unknown IP'}</p>
                                            <p className="text-[8px] font-bold text-slate-600 truncate max-w-[150px]" title={log.user_agent}>{log.user_agent}</p>
                                        </td>
                                        <td className="px-8 py-6 text-right">
                                            <button
                                                onClick={() => window.location.href = `/admin?tab=users&mobile=${log.mobile}`}
                                                className="inline-flex items-center space-x-2 text-indigo-400 hover:text-indigo-300 transition-colors group/btn"
                                            >
                                                <span className="text-[10px] font-black uppercase tracking-widest">History</span>
                                                <svg className="w-4 h-4 transform group-hover/btn:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7l5 5m0 0l-5 5m5-5H6" />
                                                </svg>
                                            </button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            <style>{`
                .custom-scrollbar::-webkit-scrollbar { width: 8px; height: 8px; }
                .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 20px; }
                .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #475569; }
            `}</style>
        </div>
    );
};

export default LoginLogs;

import React, { useState } from 'react';
import { rechargeWallet } from '../../api';
import { useNavigate } from 'react-router-dom';
import { Box, Typography, Button, TextField, Grid, Card, CardContent, IconButton } from '@mui/material';
import ArrowBackIcon from '@mui/icons-material/ArrowBack';
import PaymentsIcon from '@mui/icons-material/Payments';
import Subheader from '../../components/subheader';


const Recharge = () => {
    const [amount, setAmount] = useState('');
    const [points, setPoints] = useState('');
    const [loading, setLoading] = useState(false);
    const [configs, setConfigs] = useState([]);
    const [configsLoading, setConfigsLoading] = useState(true);
    const mobile = localStorage.getItem('mobile');
    const referenceid = localStorage.getItem('currentProfileId');
    const navigate = useNavigate();

    const [paymentEnabled, setPaymentEnabled] = useState(true);

    React.useEffect(() => {
        if (!referenceid) {
            console.warn("No profile selected, redirecting to chat");
            navigate('/chat');
            return;
        }
        checkPaymentStatus();
        fetchConfigs();
        const script = document.createElement('script');
        script.src = 'https://checkout.razorpay.com/v1/checkout.js';
        script.async = true;
        document.body.appendChild(script);
        return () => {
            document.body.removeChild(script);
        };
    }, []);

    const fetchConfigs = async () => {
        setConfigsLoading(true);
        try {
            const { getPublicRechargeConfigs } = await import('../../api');
            const { data } = await getPublicRechargeConfigs();
            setConfigs(data || []);
        } catch (e) {
            console.error("Failed to fetch recharge configs", e);
        } finally {
            setConfigsLoading(false);
        }
    };

    const checkPaymentStatus = async () => {
        try {
            const { getSystemSettings } = await import('../../api');
            const { data } = await getSystemSettings();
            if (data && typeof data.payment_enabled !== 'undefined') {
                setPaymentEnabled(data.payment_enabled);
            }
        } catch (e) {
            console.error("Failed to check payment status", e);
        }
    };

    const handleRecharge = async () => {
        if (!amount || amount <= 0) {
            alert("Please enter a valid amount");
            return;
        }

        if (!paymentEnabled) {
            alert("Payments are currently disabled by the administrator.");
            return;
        }

        setLoading(true);
        try {
            // Import dynamically to avoid circular dependency issues if any
            const { createPaymentOrder, verifyPayment } = await import('../../api');

            // 1. Create Order
            const orderRes = await createPaymentOrder(parseFloat(amount), mobile, referenceid);
            const order = orderRes.data;

            // 2. Open Razorpay
            const options = {
                key: order.key,
                amount: order.amount,
                currency: order.currency,
                name: "Astrology Guruji",
                description: "Wallet Recharge",
                order_id: order.order_id,
                handler: async function (response) {
                    try {
                        // 3. Verify Payment
                        await verifyPayment({
                            razorpay_order_id: response.razorpay_order_id,
                            razorpay_payment_id: response.razorpay_payment_id,
                            razorpay_signature: response.razorpay_signature
                        });
                        alert("Recharge Successful!");
                        navigate('/wallet');
                    } catch (err) {
                        console.error("Verification failed", err);
                        alert("Payment verification failed. Please contact support.");
                    }
                },
                prefill: {
                    contact: mobile,
                },
                theme: {
                    color: "#F26A2E"
                }
            };

            const rzp = new window.Razorpay(options);
            rzp.on('payment.failed', function (response) {
                alert("Payment Failed: " + response.error.description);
            });
            rzp.open();

        } catch (error) {
            console.error("Recharge init failed:", error);
            alert("Failed to initiate payment. Please try again.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <Box sx={{
            height: '100vh',
            display: 'flex',
            flexDirection: 'column',
            bgcolor: '#FFF6EB',
            overflow: 'hidden',

        }}>
            <Box sx={{ position: 'relative', flexShrink: 0, zIndex: 100, bgcolor: '#FFF6EB' }}>
                <Subheader title={'Recharge'} showBack onBack={() => navigate('/wallet')} />
            </Box>

            <Box sx={{
                flex: 1,
                overflowY: 'auto',
                position: 'relative',
                zIndex: 10,
                px: 3,
                pb: 5,
                pt: 3,
                "&::-webkit-scrollbar": {
                    display: "none",
                },
                scrollbarWidth: "none",
            }}>

                {!paymentEnabled && (
                    <Box sx={{ mb: 2, p: 2, bgcolor: '#FFEBEE', color: '#D32F2F', borderRadius: 2, fontSize: '0.85rem', fontWeight: 700, textAlign: 'center' }}>
                        ⚠️ Payments are currently paused.
                    </Box>
                )}

                <Card sx={{ borderRadius: 4, mb: 4, boxShadow: '0 4px 20px rgba(0,0,0,0.05)' }}>
                    <CardContent sx={{ p: 4 }}>
                        <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, mb: 4, mt: 2 }}>
                            <Box sx={{ width: 50, height: 50, bgcolor: '#FFF0E6', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                                <PaymentsIcon sx={{ color: '#F26A2E' }} />
                            </Box>
                            <Box>
                                <Typography variant="subtitle2" sx={{ fontWeight: 800, color: '#F26A2E', textTransform: 'uppercase' }}>Universal Recharge</Typography>
                                <Typography variant="caption" sx={{ color: '#888' }}>Instant balance update</Typography>
                            </Box>
                        </Box>

                        <Typography sx={{ mb: 1, fontWeight: 700, color: '#333', fontSize: '0.9rem' }}>Enter Amount (₹)</Typography>
                        <TextField
                            fullWidth
                            variant="outlined"
                            type="number"
                            value={amount}
                            onChange={(e) => setAmount(e.target.value)}
                            placeholder="0.00"
                            InputProps={{
                                sx: {
                                    borderRadius: 3,
                                    fontSize: '1.5rem',
                                    fontWeight: 800,
                                    '& .MuiOutlinedInput-notchedOutline': { border: '2px solid #FFF0E6' },
                                    '&:hover .MuiOutlinedInput-notchedOutline': { borderColor: '#F26A2E' },
                                    '&.Mui-focused .MuiOutlinedInput-notchedOutline': { borderColor: '#F26A2E' }
                                }
                            }}
                        />

                        <Box sx={{ mt: 4, mb: 4 }}>
                            <Typography sx={{ mb: 2, fontWeight: 700, color: '#666', fontSize: '0.75rem', textTransform: 'uppercase' }}>Available Packages</Typography>
                            {configsLoading ? (
                                <Typography sx={{ fontSize: '0.75rem', color: '#888' }}>Loading offers...</Typography>
                            ) : (
                                <Grid container spacing={2}>
                                    {configs.map(config => (
                                        <Grid item xs={6} key={config.config_id}>
                                            <Button
                                                fullWidth
                                                variant={amount == config.amount ? "contained" : "outlined"}
                                                onClick={() => setAmount(config.amount)}
                                                sx={{
                                                    borderRadius: 3,
                                                    p: 2,
                                                    display: 'flex',
                                                    flexDirection: 'column',
                                                    alignItems: 'center',
                                                    gap: 0.5,
                                                    borderColor: '#FFF0E6',
                                                    bgcolor: amount == config.amount ? '#F26A2E' : 'white',
                                                    color: amount == config.amount ? 'white' : '#333',
                                                    boxShadow: amount == config.amount ? '0 4px 15px rgba(242,106,46,0.2)' : 'none',
                                                    '&:hover': {
                                                        borderColor: '#F26A2E',
                                                        bgcolor: amount == config.amount ? '#F26A2E' : '#FFF0E6'
                                                    }
                                                }}
                                            >
                                                <Typography sx={{ fontWeight: 900, fontSize: '1.1rem' }}>₹{config.amount}</Typography>
                                                <Typography sx={{
                                                    fontSize: '0.65rem',
                                                    fontWeight: 800,
                                                    color: amount == config.amount ? 'white' : '#F26A2E',
                                                    textTransform: 'uppercase',
                                                    letterSpacing: 0.5
                                                }}>
                                                    {config.points} Points
                                                </Typography>
                                            </Button>
                                        </Grid>
                                    ))}
                                    {configs.length === 0 && !configsLoading && (
                                        <Grid item xs={12}>
                                            <Typography sx={{ fontSize: '0.75rem', color: '#888', fontStyle: 'italic' }}>No packages available. Enter a custom amount above.</Typography>
                                        </Grid>
                                    )}
                                </Grid>
                            )}
                        </Box>

                        <Button
                            fullWidth
                            variant="contained"
                            disabled={loading || !amount}
                            onClick={handleRecharge}
                            sx={{
                                py: 2,
                                borderRadius: 3,
                                bgcolor: '#F26A2E',
                                fontWeight: 900,
                                fontSize: '1rem',
                                textTransform: 'none',
                                boxShadow: '0 8px 25px rgba(242,106,46,0.3)',
                                '&:hover': { bgcolor: '#FF8338' },
                                '&.Mui-disabled': { bgcolor: '#FFD7C4', color: 'white' }
                            }}
                        >
                            {loading ? 'Manifesting Credits...' : 'Proceed to Payment'}
                        </Button>
                    </CardContent>
                </Card>

                <Box sx={{ p: 2, bgcolor: '#FFF0E6', borderRadius: 3, textAlign: 'center' }}>
                    <Typography variant="caption" sx={{ color: '#A0522D', fontWeight: 600 }}>
                        Secure Payment Gateway • Instant Credits • 24/7 Support
                    </Typography>
                </Box>
            </Box>
        </Box>
    );
};

export default Recharge;

import React, { useState, useEffect } from 'react';
import { getBalance, getTransactionHistory } from '../../api';
import { useNavigate } from 'react-router-dom';
import { Box, Typography, Card, CardContent, Divider } from '@mui/material';
import Subheader from '../../components/subheader';
import PrimaryButton from '../../components/PrimaryButton';
import WalletOutlinedIcon from '@mui/icons-material/WalletOutlined';

const RechargeHistory = () => {
    const [balance, setBalance] = useState(0);
    const [history, setHistory] = useState([]);
    const [loading, setLoading] = useState(true);
    const mobile = localStorage.getItem('mobile');
    const navigate = useNavigate();

    useEffect(() => {
        if (!mobile) {
            navigate('/');
            return;
        }
        fetchWalletData();
    }, [mobile]);

    const fetchWalletData = async () => {
        try {
            const balanceRes = await getBalance(mobile);
            setBalance(balanceRes.data.balance || 0);

            const historyRes = await getTransactionHistory(mobile);
            // Filter only credit transactions (recharges)
            const rechargeHistory = (historyRes.data.history || []).filter(tx => tx.type === 'credit');
            setHistory(rechargeHistory);
        } catch (error) {
            console.error("Error fetching wallet data:", error);
        } finally {
            setLoading(false);
        }
    };

    return (
        <Box sx={{
            height: '100vh',
            display: 'flex',
            flexDirection: 'column',
            bgcolor: '#FFF6EB',
            overflow: 'hidden'
        }}>
            <Box sx={{ position: 'relative', flexShrink: 0, zIndex: 100, bgcolor: '#FFF6EB' }}>
                <Subheader title="Recharge history" showBack />
            </Box>

            <Box sx={{
                flex: 1,
                overflowY: 'auto',
                position: 'relative',
                zIndex: 10,
                mt: 9,
                pt: 4,
                px: 2,
                pb: 5,
                '&::-webkit-scrollbar': { display: 'none' },
                msOverflowStyle: 'none',
                scrollbarWidth: 'none'
            }}>
                {/* Balance Card */}
                <Card sx={{
                    borderRadius: 1,
                    mb: 1,
                    boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
                    border: '1px solid #eee'
                }}>
                    <CardContent sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', py: 2, '&:last-child': { pb: 2 } }}>
                        <Box sx={{ display: 'flex', alignItems: 'center' }}>
                            <WalletOutlinedIcon sx={{ color: '#dc5d35', mr: 1, fontSize: 30 }} />
                            <Typography sx={{ fontWeight: 700, color: '#dc5d35', fontSize: '1rem' }}>
                                Wallet balance: <Box component="span" sx={{ color: '#333' }}>₹{balance.toLocaleString()} </Box>
                            </Typography>
                        </Box>
                        <PrimaryButton
                            label="Recharge now"
                            onClick={() => navigate('/wallet')}
                            sx={{
                                bgcolor: '#54a170',
                                color: '#fff',
                                borderRadius: 50,
                                textTransform: 'none',
                                fontWeight: 500,
                                p: .5,
                                width: '130px',
                                fontSize: '0.9rem',
                                '&:hover': { bgcolor: '#458a5c' }
                            }}
                        />
                    </CardContent>
                </Card>

                {/* History List */}
                <Box>
                    {loading ? (
                        <Typography sx={{ textAlign: 'center', mt: 4, color: '#666' }}>Loading...</Typography>
                    ) : history.length === 0 ? (
                        <Typography sx={{ textAlign: 'center', mt: 4, color: '#666' }}>No recharge history found.</Typography>
                    ) : (
                        history.map((tx, index) => (
                            <Card key={index} sx={{
                                borderRadius: 1,
                                mb: 1,
                                boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
                                border: '1px solid #eee'
                            }}>
                                <CardContent sx={{ py: 2, '&:last-child': { pb: 2 } }}>
