    dobyear = form.dobyear.value;
    h = pInt(form.tobhour.value) + (form.ampm[0].checked ? 0 : 12);
    h = (h == 24 ? 12 : (h == 12 ? 0 : h));
    tob = h + ":" + form.tobmin.value;
